VALUES
  ('judicial-57f41407-moex-00623', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「快時尚產業意指：在極短時間內推出時裝週展出的服飾，讓消費者可以在短時間內以平易近人的低 廉價格買到最新（但可能低品質）的服飾。過去時尚產業季節主要集中在夏季和秋冬，但來到 2014 年，瞄準快速消費的快時尚產業已將之拆分成52個『微時尚季』，其背後促成的消費概念即是：讓消 費者不斷追求最新的潮流服飾，盡可能購買更多服飾。」 根據上文，下列選項何者正確？', '["原先的時尚產業能讓人以最平易的價格買到最精緻的衣服", "快時尚的目的是為了刺激生產，使時尚產業得以革新創發", "快時尚的產業季節變為52季，因此得一直辦理時裝週活動", "原先的時尚產季拆分為微時尚季，讓消費者持續提高購買慾望"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
